-- ── Roles: EMPLOYEE for all ────────────────────────────────
INSERT INTO user_roles (user_id, role_id)
SELECT u.id, r.id FROM users u, roles r
WHERE u.id IN (
  SELECT id FROM users WHERE id LIKE '66660%'
    AND id LIKE '%-0000-0000-0000-000000000001'
) AND r.name = 'EMPLOYEE'
ON CONFLICT DO NOTHING;

